sys_security_acl.script:
answer = (function canViewConfiguredSensorParam(grCurrentSensorParam) {

	var grConfiguredSensor;

	//Return true if user can view the parent configured action.
	grConfiguredSensor = grCurrentSensorParam.configured_sensor.getRefRecord();
	if (!grConfiguredSensor.isValidRecord()) {
		//If the Configured Sensor that this Configured Sensor Parameter references doesn't exist, return false.
		return false;
	}
	return !!grConfiguredSensor.canRead();

})(current);
